#!/usr/bin/env bash
# Snyk Studio Recipes — self-extracting installer (generated; do not edit)
set -euo pipefail

Main() {
  local workdir
  local bundle
  local archive

  EnsureUvOnPath
  EnsureUv "$@"

  workdir="$(mktemp -d "${TMPDIR:-/tmp}/snyk-studio-install.XXXXXX")"
  cleanup() { rm -rf "${workdir:-}"; }
  trap cleanup EXIT INT TERM
  # Export name is a build-time placeholder; build_installer rewrites it to SNYK_STUDIO_BUNDLE_ROOT.
  export SNYK_STUDIO_BUNDLE_ROOT="$workdir"

  bundle="$workdir/bundle.base64"
  WriteEmbeddedPayload "$bundle"

  archive="$workdir/bundle.tar.gz"
  DecodeBase64Bundle "$bundle" "$archive"
  ExpandArchive "$archive" "$workdir"
  rm -f "$archive"

  uv run "$workdir/snyk-studio-installer.py" "$@"
}

# Common install location for uv (astral.sh installer); prepend so a fresh install is visible.
EnsureUvOnPath() {
  case "${HOME:-}" in
    "") ;;
    *) export PATH="${HOME}/.local/bin:${PATH}" ;;
  esac
}

EnsureUv() {
  local auto_yes=0
  local arg
  for arg in "$@"; do
    if [[ "$arg" == "-y" || "$arg" == "--yes" ]]; then
      auto_yes=1
      break
    fi
  done

  if command -v uv >/dev/null 2>&1; then
    echo "  OK uv $(uv --version 2>/dev/null | head -n 1)"
    return 0
  fi

  echo "  WARNING uv not found" >&2
  echo "    Install with: curl -LsSf https://astral.sh/uv/install.sh | sh" >&2

  if [[ "$auto_yes" -eq 0 ]]; then
    printf '\n  Install uv now? (y/n) '
    IFS= read -r reply || true
    reply="$(printf '%s' "$reply" | tr '[:upper:]' '[:lower:]' | tr -d '[:space:]')"
    if [[ "$reply" != "y" && "$reply" != "yes" ]]; then
      echo "  Cancelled: uv is required to run this installer." >&2
      exit 1
    fi
  fi

  if command -v curl >/dev/null 2>&1; then
    curl -LsSf https://astral.sh/uv/install.sh | sh
  elif command -v wget >/dev/null 2>&1; then
    wget -qO- https://astral.sh/uv/install.sh | sh
  else
    echo "  Error: need curl or wget to install uv." >&2
    exit 1
  fi

  EnsureUvOnPath
  if ! command -v uv >/dev/null 2>&1; then
    echo "  Error: uv was installed but is not on PATH. Add ~/.local/bin to PATH and retry." >&2
    exit 1
  fi
}

WriteEmbeddedPayload() {
  local bundle="$1"
  local payload

  local marker='__SNYK_STUDIO_BUNDLE_B64__'
  local foundBundleMarker=0
  local line
  local b64_payload=""

  while IFS= read -r line || [[ -n "${line:-}" ]]; do
    if [[ "$foundBundleMarker" -eq 0 ]]; then
      if [[ "$line" == "$marker" ]]; then
        foundBundleMarker=1
      fi
      continue
    fi
    line="${line//$'\r'/}"
    b64_payload+="$line"
  done < "$0"

  if [[ "$foundBundleMarker" -eq 0 ]]; then
    echo "Error: missing bundle marker in $0" >&2
    exit 1
  fi

  printf '%s' "$b64_payload" > "$bundle"
}

DecodeBase64Bundle() {
  local bundle="$1"
  local archive="$2"

  rm -f "$archive"
  if command -v openssl >/dev/null 2>&1; then
    cat "$bundle" | openssl base64 -d -A -out "$archive" 2>/dev/null || true
  fi
  if [[ ! -s "$archive" ]] && echo YQ== | base64 -d >/dev/null 2>&1; then
    cat "$bundle" | base64 -d >"$archive" 2>/dev/null || true
  fi
  if [[ ! -s "$archive" ]] && echo YQ== | base64 --decode >/dev/null 2>&1; then
    cat "$bundle" | base64 --decode >"$archive" 2>/dev/null || true
  fi
  if [[ ! -s "$archive" ]] && echo YQ== | base64 -D >/dev/null 2>&1; then
    cat "$bundle" | base64 -D >"$archive" 2>/dev/null || true
  fi
  if [[ ! -s "$archive" ]]; then
    echo "Error: need openssl or base64 to decode the embedded bundle (decoded file empty)." >&2
    exit 1
  fi
}

ExpandArchive() {
  local archive="$1"
  local workdir="$2"
  if ! tar xzf "$archive" -C "$workdir"; then
    echo "Error: tar failed to extract bundle (need GNU/BSD tar with gzip)." >&2
    exit 1
  fi
}

Main "$@"
exit $?
